+import FluidAudio
+import Foundation
+
+protocol FluidAudioRuntimeLoading: AnyObject, Sendable {
+    func isCached(versionIdentifier: String) async throws -> Bool
+    func download(versionIdentifier: String, progress: @escaping @Sendable (Double) -> Void) async throws
+    func load(versionIdentifier: String) async throws
+    func transcribe(audioSamples: [Float]) async throws -> String?
+    func reset() async
+}
+
+@MainActor
+final class FluidAudioSpeechModelLoader: SpeechModelLoading {
+    private let runtime: any FluidAudioRuntimeLoading
+
+    init(runtime: any FluidAudioRuntimeLoading = FluidAudioRuntimeBridge()) {
+        self.runtime = runtime
+    }
+
+    func isCached(_ model: SpeechModelDescriptor) async throws -> Bool {
+        try await runtime.isCached(versionIdentifier: variantIdentifier(for: model))
+    }
+
+    func download(_ model: SpeechModelDescriptor, progress: @escaping @Sendable (Double) -> Void) async throws {
+        try await runtime.download(
+            versionIdentifier: variantIdentifier(for: model),
+            progress: progress
+        )
+    }
+
+    func load(_ model: SpeechModelDescriptor, whisperOptions: WhisperRuntimeOptions) async throws {
+        _ = whisperOptions
+        try await runtime.load(versionIdentifier: variantIdentifier(for: model))
+    }
+
+    func resetLoadedModels() async {
+        await runtime.reset()
+    }
+
+    private func variantIdentifier(for model: SpeechModelDescriptor) throws -> String {
+        guard model.backend == .fluidAudio, let fluidAudioVariant = model.fluidAudioVariant else {
+            throw FluidAudioSpeechModelLoaderError.invalidConfiguration(model.id)
+        }
+
+        return fluidAudioVariant
+    }
+}
+
+@MainActor
+final class CompositeSpeechModelLoader: SpeechModelLoading {
+    private let whisperLoader: any SpeechModelLoading
+    private let fluidAudioLoader: any SpeechModelLoading
+
+    init(
+        whisperLoader: any SpeechModelLoading,
+        fluidAudioLoader: any SpeechModelLoading
+    ) {
+        self.whisperLoader = whisperLoader
+        self.fluidAudioLoader = fluidAudioLoader
+    }
+
+    func isCached(_ model: SpeechModelDescriptor) async throws -> Bool {
+        try await loader(for: model).isCached(model)
+    }
+
+    func download(_ model: SpeechModelDescriptor, progress: @escaping @Sendable (Double) -> Void) async throws {
+        try await loader(for: model).download(model, progress: progress)
+    }
+
+    func load(_ model: SpeechModelDescriptor, whisperOptions: WhisperRuntimeOptions) async throws {
+        try await loader(for: model).load(model, whisperOptions: whisperOptions)
+    }
+
+    func resetLoadedModels() async {
+        await whisperLoader.resetLoadedModels()
+        await fluidAudioLoader.resetLoadedModels()
+    }
+
+    private func loader(for model: SpeechModelDescriptor) -> any SpeechModelLoading {
+        switch model.backend {
+        case .whisper:
+            return whisperLoader
+        case .fluidAudio:
+            return fluidAudioLoader
+        }
+    }
+}
+
+actor FluidAudioRuntimeBridge: FluidAudioRuntimeLoading {
+    private var asrManager: AsrManager?
+    private var pendingModelsByVersion: [String: AsrModels] = [:]
+
+    func isCached(versionIdentifier: String) async throws -> Bool {
+        let version = try resolvedVersion(for: versionIdentifier)
+        return AsrModels.modelsExist(
+            at: AsrModels.defaultCacheDirectory(for: version),
+            version: version
+        )
+    }
+
+    func download(versionIdentifier: String, progress: @escaping @Sendable (Double) -> Void) async throws {
+        let version = try resolvedVersion(for: versionIdentifier)
+        let models = try await AsrModels.downloadAndLoad(version: version) { downloadProgress in
+            progress(downloadProgress.fractionCompleted)
+        }
+        pendingModelsByVersion[versionIdentifier] = models
+    }
+
+    func load(versionIdentifier: String) async throws {
+        let version = try resolvedVersion(for: versionIdentifier)
+        let models = if let downloadedModels = pendingModelsByVersion.removeValue(forKey: versionIdentifier) {
+            downloadedModels
+        } else {
+            try await AsrModels.load(
+                from: AsrModels.defaultCacheDirectory(for: version),
+                version: version
+            )
+        }
+
+        let manager = AsrManager(config: .default)
+        try await manager.loadModels(models)
+        asrManager = manager
+    }
+
+    func transcribe(audioSamples: [Float]) async throws -> String? {
+        guard let asrManager else {
+            return nil
+        }
+
+        let result = try await asrManager.transcribe(audioSamples, source: .microphone)
+        return result.text
+    }
+
+    func reset() async {
+        asrManager = nil
+        pendingModelsByVersion.removeAll()
+    }
+
+    private func resolvedVersion(for versionIdentifier: String) throws -> AsrModelVersion {
+        switch versionIdentifier {
+        case "v3":
+            return .v3
+        default:
+            throw FluidAudioSpeechModelLoaderError.invalidConfiguration(versionIdentifier)
+        }
+    }
+}
+
+private enum FluidAudioSpeechModelLoaderError: LocalizedError {
+    case invalidConfiguration(String)
+
+    var errorDescription: String? {
+        switch self {
+        case let .invalidConfiguration(identifier):
+            return "Speech model configuration is invalid for \(identifier)."
+        }
+    }
+}

